let data = [];
let scrape = $('Prepare Data').first().json.data.scrape;
// Loop over input items and add a new field called 'myNewField' to the JSON of each one

Object.entries($('Prepare Data').first().json.data.manual).forEach(([key, value]) => {
  if(key != 'images' && key != 'app_url' && key != 'app_deadline'){
    data.push({
      label: key.replace("_", " "),
      value: value
    })
  }
});
let social = {
  intent: $('Prepare Data').first().json.config.intent,
  branding: $('Prepare Data').first().json.config.branding,
  persona: $('Prepare Data').first().json.config.persona,
  jobUrl: $('Prepare Data').first().json.data.manual.app_url,
  jobDeadline: $('Prepare Data').first().json.data.manual.app_deadline,
  language: $('Prepare Data').first().json.config.language,
  type: $('Prepare Data').first().json.config.mediaType,
  additionalPrompt: $('Prepare Data').first().json.config.additionalPrompt
};
if($input.first().json.config.mediaType == 'image'){
  social.maxImage = $('Prepare Data').first().json.config.maxImage;
}
return {
  data: [...data, ...scrape],
  config: social
}

return{
  desc: $input.first().json.content.parts[0].text,
  url: $('Loop Over Items').first().json.url,
  binary: $('Loop Over Items').first().json.binary,
  mime: $('Loop Over Items').first().json.mime
}

let finalPrompt = [];
for (const item of $('Prompt Data').first().json.prompts) {
  let description = '';
  let n = 1;
  for (const parsed of $input.first().json.parsed) {
    description += 'Description of image '+n+':\n\r'+parsed.desc+'\n\r';
    n++
  }
  finalPrompt.push(description+'\n\r'+ 'Target Prompt:\n\r'+item.prompt);
}
return {finalPrompt:finalPrompt};

const result = JSON.parse($input.first().json.content.parts[0].text);

const prompt = result.final_prompt;

// Prepare the parts array with the text prompt first
const parts = [
  { text: prompt },
  { text: JSON.stringify($('Prompt Data').first().json.campaignDesignSystem) },
];

// Loop through all incoming items and extract images
// Note: If all images are in one item as different binary keys, adjust the loop.
// This assumes multiple items (e.g., 3 separate image items).
let x = 1;
for (const item of $('Prepare Image').first().json.parsed) {
  if (!result.excluded_images.includes(x)) {
parts.push({
      inlineData: {
        mimeType: item.mime,
        data: item.binary // n8n already provides this as base64
      }
    });
  }
 x++;
}

// Return the structure ready for the API
return {
  json: {
    payload: {
      contents: [
        {
          parts: parts
        }
      ],
      generationConfig: {
          responseModalities: ["image"],
          topP: 0.2,
          imageConfig:{
              aspectRatio: $('Prepare Data').first().json.config.imgRatio
          }
      }
    }
  }
};

function getValidJsonObject(rawText) {

    if (typeof rawText !== 'string' || rawText.trim() === '') {
        console.error("Invalid input or empty text field.");
        return null;
    }

    let jsonString = rawText.trim();

    // 2. Check for and remove the markdown JSON block fences.
    // This regex is robust and handles variations in whitespace.
    const markdownRegex = /^```json\s*([\s\S]*?)\s*```$/;
    const match = jsonString.match(markdownRegex);

    if (match) {
        // If it's a match, the actual JSON string is in the first capture group.
        jsonString = match[1];
    }

    // 3. Parse the cleaned string into a JSON object.
    try {
        return JSON.parse(jsonString);
    } catch (error) {
        console.error("Failed to parse JSON string:", error);
        console.error("Problematic string:", jsonString);
        return null;
    }
}
let result = getValidJsonObject($input.first().json.content.parts[0].text);

return result;

const parts = [
  { text: $input.first().json.prompt },
  { text: JSON.stringify($('Prompt Data').first().json.campaignDesignSystem) },
];


// Return the structure ready for the API
return {
  json: {
    payload: {
      contents: [
        {
          parts: parts
        }
      ],
      generationConfig: {
          responseModalities: ["image"],
          topP: 0.2,
          imageConfig:{
              aspectRatio: $('Prepare Data').first().json.config.imgRatio
          }
      }
    }
  }
};

let images = [];
for (const item of $input.first().json.images) {
  images.push({
    mime: item.candidates[0].content.parts[0].inlineData.mimeType,
    data: item.candidates[0].content.parts[0].inlineData.data
  })
}

return {
  images: images,
  caption:$input.first().json.caption,
  language: $input.first().json.language,
  account: $input.first().json.account,
  domain: $input.first().json.domain,
  license: $input.first().json.license,
  service_id: $input.first().json.service_id
}
